package main

import "math"

func solve(nums []int64) int64 {
	if len(nums) == 0 {
		return 0
	}

	// 1. Find the set of unique values U in nums.
	uniqueMap := make(map[int64]bool)
	for _, num := range nums {
		uniqueMap[num] = true
	}

	// Extract and sort unique values U.
	var U []int64
	for num := range uniqueMap {
		U = append(U, num)
	}
	// Sort U in ascending order.
	for i := 0; i < len(U); i++ {
		for j := i + 1; j < len(U); j++ {
			if U[i] > U[j] {
				U[i], U[j] = U[j], U[i]
			}
		}
	}

	var totalMinSum int64 = 0

	// 2. For each nums[i], find m_i = min {u in U | u divides nums[i]}.
	// 3. The minimum sum is sum(m_i).
	for _, originalNum := range nums {
		// Since U is sorted, the first u we find that divides originalNum will be the smallest.
		smallestDivisorInU := originalNum
		found := false
		for _, u := range U {
			if u > originalNum {
				break // Optimization: u cannot divide originalNum if u > originalNum
			}
			if originalNum%u == 0 {
				smallestDivisorInU = u
				found = true
				break // Found the smallest divisor in U
			}
		}

		// If for some reason no divisor was found (shouldn't happen as originalNum is in U), 
		// smallestDivisorInU remains originalNum.
		totalMinSum += smallestDivisorInU
	}

	return totalMinSum
}
