package main

import (
	"sort"
)

// GCD function (although not strictly needed by the final derived algorithm, 
// it's good practice if the GCD theory were correct).
func gcd(a, b int64) int64 {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func solve(nums []int64) int64 {
	if len(nums) == 0 {
		return 0
	}

	// 1. Find the set of unique values U in nums.
	uniqueSet := make(map[int64]bool)
	for _, num := range nums {
		uniqueSet[num] = true
	}

	// Convert to a sorted slice U. Sorting allows us to find the minimum divisor efficiently.
	U := make([]int64, 0, len(uniqueSet))
	for num := range uniqueSet {
		U = append(U, num)
	}
	sort.Slice(U, func(i, j int) bool {
		return U[i] < U[j]
	})

	var minSum int64 = 0

	// 2. For each original num, find m_i = min {u in U | u divides originalNum}.
	for _, originalNum := range nums {
		smallestDivisorInU := originalNum // Initialize with itself (which is in U)

		// Since U is sorted, the first element u that divides originalNum is the smallest such element.
		for _, u := range U {
			if u > originalNum {
				break // Optimization: no need to check larger unique numbers
			}
			if originalNum%u == 0 {
				smallestDivisorInU = u
				break
			}
		}
		// 3. Accumulate the result
		minSum += smallestDivisorInU
	}

	return minSum
}
